window.fweIcon = function(name, size, color){
  size = size || 24;
  var d = window.FWE_ICON_DATA[name];
  if(!d){ console.warn('fweIcon: unknown icon', name); return ''; }
  var col = color || 'currentColor';
  // Many icons declare stroke="currentColor" + strokeWidth on the <svg> root.
  // Apply outline defaults on the root so child paths inherit them; paths that
  // set their own stroke/fill still override. Filled icons (rootFill currentColor)
  // get fill instead and no stroke.
  var filled = d.rootFill === 'currentColor';
  var fill = filled ? 'currentColor' : 'none';
  var stroke = filled ? 'none' : 'currentColor';
  return '<svg xmlns="http://www.w3.org/2000/svg" width="'+size+'" height="'+size+'" viewBox="0 0 24 24"'
    + ' fill="'+fill+'" stroke="'+stroke+'" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"'
    + ' style="color:'+col+';display:block;flex-shrink:0" aria-hidden="true">'+d.body+'</svg>';
};
